{
	stub := ctx.GetStub()
	instance, err := cc.GetInstance(ctx, instanceID)
	gtw, err := cc.ReadGtw(ctx, instanceID, "DecisionA")
	if err != nil {
		return err
	}

	if gtw.GatewayState != ENABLED {
		errorMessage := fmt.Sprintf("Gateway state %s is not allowed", gtw.GatewayID)
		fmt.Println(errorMessage)
		return fmt.Errorf(errorMessage)
	}

	cc.ChangeGtwState(ctx, instance, gtw.GatewayID, COMPLETED)
	stub.SetEvent("DecisionA", []byte("Gateway has been completed"))
	cc.SetInstance(ctx, instance)
	if instance.InstanceStateMemory.ApprovedA == true {
		cc.ChangeMsgState(ctx, instance, "ConfirmA", ENABLED)
	} else {
		cc.ChangeEventState(ctx, instance, "EndEvent_A", ENABLED)
	}

	cc.SetInstance(ctx, instance)

	return nil
}

